import{_ as e,o as a,c as i,ae as n}from"./chunks/framework.RRduUuAx.js";const p=JSON.parse(`{"title":"Let's install!","description":"","frontmatter":{"next":{"text":"Choose an Installation Method!","link":"installation#choosing-a-method-of-installation"}},"headers":[],"relativePath":"ps4/installation-variants.md","filePath":"ps4/installation-variants.md","lastUpdated":null}`),o={name:"ps4/installation-variants.md"};function l(s,t,r,h,c,d){return a(),i("div",null,[...t[0]||(t[0]=[n('<div class="danger custom-block github-alert"><p class="custom-block-title">DANGER</p><p>NOTE: You <strong>CAN</strong> infact install it &quot;permanently&quot; by having a device externally or internally(as a modchip) to boot linux on boot if youre firmware is beetween 9.00 and 11.00 but the process is very hard to document so i suggest looking at <a href="https://www.youtube.com/@MODDEDWARFARE" target="_blank" rel="noreferrer">MODDED_WAREFARE&#39;s</a> channel</p></div><h1 id="let-s-install" tabindex="-1">Let&#39;s install! <a class="header-anchor" href="#let-s-install" aria-label="Permalink to &quot;Let&#39;s install!&quot;">​</a></h1><p>Installing Linux on the PS4 is unsurprisingly difficult.</p><details class="details custom-block"><summary>Internal vs External: The Finale - GOTY Limited Edition (rant)</summary><p>As I&#39;ve mentioned beforehand, you can&#39;t install Linux on the internal PS4&#39;s HDD on Baikal systems. Technically you can but the system is very broken and borderline unusable so its <strong>HIGHLY</strong> not recommended. To give you an explanation, it took Dionkill 30 MINUTES to update his CachyOS installation (1500MBs) and the system was so unresponsive that he could watch entire anime episodes in between clicks.</p><p>Using an external SATA-USB adapter with a Samsung 870 EVO 500GB, the time it took shrinked to less than 5 minutes, same when using it as the internal drive.</p><p>Therefore, to clear some misinformation here:</p><ul><li>The PS4&#39;s internal HDD is a repurposed laptop 5400RPM drive. Please, do NOT use this. Even the PS4&#39;s own menus lag because of how slow it is.</li><li>The PS4 internal drive uses UFS encryption so it slows down significantly, even if you swap in an SSD.</li><li>You CAN clone your PS4 HDD into an SSD, if internal installation is a must for you.</li><li>The PS4 doesn&#39;t support TRIM, so a possible internal SSD swap would be a lot slower in writing data (a quality cached SSD with a garbage collector would be a bit better though).</li><li>PS4 Phat and Slim are limited to SATA-II, which is 3Gbps in speed (roughly 375MB/s), which people online say it&#39;s not enough (it&#39;s enough for a PS4). On the other hand, the PS4 Pro runs at SATA-III, which is 6Gbps (up to 750MB/s), so that can saturate every SATA SSD on the market. <ul><li>External SSD, on my 500GB Samsung 870 EVO, is 350MB/s-ish. So you&#39;d get the same performance as an internal drive (theoretically) even on a Slim/Phat console.</li><li>Internal SSD performance is similar to external, because both of them use the USB bus, however encryption will slow down I/O access.</li></ul></li></ul><p>An internal SSD is going to be much faster and probably more reliable than a USB drive (which constantly disconnects, too), so it&#39;s recommended, just remember to get a good quality one as the PS4 doesn&#39;t support TRIM.</p></details><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>TL;DR:</p><p>Internal HDD is only for Aeolia/Belize, not recommended (unless you have switched to an SSD). Every console supports external, which is recommend with an SSD via an adapter.</p></div><h2 id="preparing-the-installation" tabindex="-1">Preparing the installation <a class="header-anchor" href="#preparing-the-installation" aria-label="Permalink to &quot;Preparing the installation&quot;">​</a></h2><ol><li>Boot your PS4 and launch GoldHen.</li><li>Take the initramfs.zip file, open it, and choose your installation method (mind the Southbridge) <ul><li>Put it somewhere like on your desktop as we&#39;ll need it</li></ul></li><li>Choose your kernel of choice</li><li>Choose your distro and and rename it <code>psxitarch.tar.xz/gz</code> depending on the original file type</li></ol><h2 id="choosing-a-method-of-installation" tabindex="-1">Choosing a method of installation <a class="header-anchor" href="#choosing-a-method-of-installation" aria-label="Permalink to &quot;Choosing a method of installation&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Choose ONLY ONE method of installation.</p><p>Installing on both the internal and external drives can cause problems! If you did, remove one of the previous installations!</p></div><p>Here you will choose a method of installation.</p><p>Again, choose only one method and stick with it, and remember that Baikal can&#39;t currently install to internal reliably.</p><div class="tip custom-block"><p class="custom-block-title">Internal Installation</p><p>This method installs Linux on the internal PS4 HDD, by creating a partition as big as you want. It will not overwrite anything on the drive.</p><p><a href="/internal-installation.html">Internal Installation section.</a></p></div><div class="tip custom-block"><p class="custom-block-title">External Installation</p><p>For external installation, there are two methods: the first one involving a script on the PS4 (faster to configure), and another one with manual partitioning (higher success rate).</p><p>What does &quot;higher success rate&quot; mean, basically the installation can fail for various reasons like bad kernel, initramfs or just the distro itself and sometimes its just because the console felt like it.</p><p>The manual partitioning method is indeed preferred, but it involves the use of a Linux computer, virtual machine, or WSL2 on Windows. You may choose the scripted method, however if any issues arise, try the other one.</p><p><a href="/external-installation-scripted.html">Scripted External Installation.</a></p><p><a href="/external-installation-manual.html">Manual External Installation.</a></p></div>',13)])])}const m=e(o,[["render",l]]);export{p as __pageData,m as default};
